const input = $input.first().json;
const businessId = input.body.businessId;
const businessName = input.body.businessName;
const businessDescription = input.body.businessDescription || '';
const category = input.body.category || 'unknown';
const opportunityData = input.body.opportunityData || {};

if (!businessId || !businessName) {
  throw new Error('Missing required fields: businessId and businessName');
}

return [{
  json: {
    businessId,
    businessName,
    businessDescription,
    category,
    opportunityData,
    startedAt: $now.toFormat('yyyy-MM-dd HH:mm:ss')
  }
}];

const prdContent = $('CEO: Generate PRD').first().json.response || $('CEO: Generate PRD').first().json.text || '';
const payload = $('Build PRD Prompt').first().json;

return [{
  json: {
    ...payload,
    prdContent,
    prdGeneratedAt: $now.toFormat('yyyy-MM-dd HH:mm:ss')
  }
}];

const reviewRaw = $('Comptroller: Review PRD').first().json.response || $('Comptroller: Review PRD').first().json.text || '{}';
const payload = $('Extract PRD Content').first().json;

let review;
try {
  review = JSON.parse(reviewRaw);
} catch (e) {
  const jsonMatch = reviewRaw.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      review = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      review = { decision: 'APPROVED', notes: 'Could not parse review, defaulting to APPROVED', raw: reviewRaw };
    }
  } else {
    review = { decision: 'APPROVED', notes: 'Could not parse review, defaulting to APPROVED', raw: reviewRaw };
  }
}

const approved = review.decision === 'APPROVED';

return [{
  json: {
    ...payload,
    reviewDecision: review.decision || 'UNKNOWN',
    reviewApproved: approved,
    reviewConfidence: review.confidence || 0,
    reviewNotes: review.notes || '',
    reviewRevenueCeiling: review.revenueCeiling || '',
    reviewDistribution: review.distributionViability || '',
    reviewCompetitiveGap: review.competitiveGap || '',
    reviewPrdQuality: review.prdQuality || '',
    reviewIntegrations: review.integrationCompleteness || ''
  }
}];
